eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   capabilities: () => (/* binding */ capabilities)\n/* harmony export */ });\nconst capabilities = [\n    {\n        id: \"ai-decision-intelligence\",\n        title: \"AI & Decision Intelligence\",\n        intro: \"Deploying practical AI to process complex institutional data, surfacing actionable insights and reducing cognitive load on decision-makers. We move beyond analytics dashboards to systems that actively augment institutional judgment.\",\n        bullets: [\n            \"Identify decisions being made badly — and precisely where AI reduces the cost of error\",\n            \"Integrate ML models into existing operational approval workflows, not alongside them\",\n            \"Deliver confidence scoring and auditability as core system requirements, not add-ons\",\n            \"Ensure human-in-the-loop architecture that earns institutional trust before expanding scope\"\n        ],\n        services: [\n            \"AI use-case identification and prioritization framework\",\n            \"Predictive resource allocation and demand forecasting models\",\n            \"Automated risk assessment with scenario modeling and probability scoring\",\n            \"Natural language processing for document analysis, compliance, and audit\",\n            \"Algorithmic decision-support dashboards with full auditability\"\n        ],\n        idealClient: \"Government agencies, infrastructure operators, or foundations that hold significant operational data but lack the systems to convert it into decision-ready intelligence. Organizations whose analysts spend more time aggregating data than interpreting it.\",\n        scenarios: [\n            \"A ministry of finance needs to flag high-risk budget allocations before they are approved — not analyze them after the fact. AI risk scoring integrated into the approval workflow surfaces anomalies in real time.\",\n            \"An infrastructure operator with 20 years of maintenance records wants to predict asset failure six months ahead. A condition-based predictive model replaces reactive maintenance scheduling.\",\n            \"A large foundation reviewing 400+ grant applications needs to surface the highest-impact candidates faster. AI scoring against defined impact criteria accelerates and standardizes the review process.\",\n            \"A utility commission needs explainable AI outputs that regulators can audit. Every model recommendation carries a confidence score, input trace, and human override log.\"\n        ],\n        deliverables: [\n            \"AI capability roadmap with prioritized use cases and ROI estimates\",\n            \"Machine learning models integrated into existing operational workflows\",\n            \"Executive decision-support dashboards with live confidence metrics\",\n            \"Auditability and model governance framework for AI-assisted decisions\"\n        ]\n    },\n    {\n        id: \"digitization-data-platforms\",\n        title: \"Digitization & Data Platforms\",\n        intro: \"Structuring disparate institutional data into secure, scalable platforms that serve as the foundation for operational intelligence. We modernize legacy operations without disrupting core institutional processes.\",\n        bullets: [\n            \"Start from the workflow, not the technology — map operational friction before specifying systems\",\n            \"Eliminate paper-based routing and email-dependent approvals in critical process chains\",\n            \"Design data architecture that is interoperable from day one, not retrofitted later\",\n            \"Build automated pipelines that deliver reporting-ready data without analyst assembly\"\n        ],\n        services: [\n            \"Legacy system assessment, modernization planning, and phased migration\",\n            \"Workflow digitization replacing paper-based routing and manual approval chains\",\n            \"Secure data lakes, warehousing, and cross-system interoperability architecture\",\n            \"Automated reporting and compliance dashboards replacing manual assembly\",\n            \"API integration across siloed departmental systems and vendor platforms\"\n        ],\n        idealClient: \"Institutions relying on manual processes, disconnected databases, or paper-based workflows for critical operations. Organizations that cannot answer basic operational questions without days of manual data collection.\",\n        scenarios: [\n            \"A state transport authority runs procurement across 14 departments on email and printed forms. Digital workflow replaces the entire routing chain — with role-based access, automatic escalations, and an audit trail.\",\n            \"A national development bank holds operational data across 8 incompatible systems. A unified data platform with a single API layer gives leadership one source of truth for the first time.\",\n            \"A public hospital group needs automated compliance reports for 3 regulatory bodies on different schedules. Automated pipelines replace the team of 5 analysts previously building these manually.\",\n            \"A CSR program is tracking disbursements, outcomes, and milestones across 60 grantees in spreadsheets. A centralized data platform with standardized input templates delivers real-time portfolio visibility.\"\n        ],\n        deliverables: [\n            \"Current-state workflow and systems architecture assessment with gap analysis\",\n            \"Unified data platform design with interoperability blueprint\",\n            \"Automated reporting system covering all departmental functions\",\n            \"Digital workflow implementation with compliance and full audit trail\"\n        ]\n    },\n    {\n        id: \"iot-smart-infrastructure\",\n        title: \"IoT & Smart Infrastructure\",\n        intro: \"Connecting physical assets to digital monitoring systems for real-time oversight and predictive maintenance in critical environments. We deploy intelligence at the edge and aggregate it into institutional command centers.\",\n        bullets: [\n            \"Design sensor architecture that fits the physical realities of the environment — not a generic spec\",\n            \"Engineer telemetry pipelines robust enough for high-volume, latency-sensitive operational contexts\",\n            \"Detect degradation patterns before failure, not after — anomaly detection as standard, not optional\",\n            \"Deliver a single operational command view across distributed multi-site asset portfolios\"\n        ],\n        services: [\n            \"Sensor deployment strategy, vendor selection, and IoT architecture design\",\n            \"Real-time telemetry integration and high-throughput data pipeline engineering\",\n            \"Anomaly detection models and predictive maintenance algorithm development\",\n            \"Edge computing implementation for bandwidth-constrained or air-gapped environments\",\n            \"Centralized asset monitoring dashboards with configurable alert and escalation rules\"\n        ],\n        idealClient: \"Infrastructure operators, transit authorities, utilities, and energy companies managing large physical asset portfolios with limited real-time visibility. Organizations responding to failures reactively rather than preventing them proactively.\",\n        scenarios: [\n            \"A metro transit authority with 300km of track has no condition data between scheduled inspections. IoT sensor deployment combined with anomaly detection converts reactive maintenance into a predictive program.\",\n            \"A water utility managing 40 pumping stations has no centralized monitoring. A telemetry integration layer aggregates data from all sites into one command dashboard — alerting operations before failures cascade.\",\n            \"An energy producer needs continuous monitoring of turbine health across 12 sites. Edge computing processes sensor data locally; critical alerts reach operators within seconds regardless of connectivity.\",\n            \"A port authority wants to reduce equipment downtime. A predictive maintenance system analyzes vibration and thermal sensors on cranes and vehicles, triggering work orders before failure occurs.\"\n        ],\n        deliverables: [\n            \"IoT architecture specification and phased sensor deployment plan\",\n            \"Live infrastructure monitoring system with real-time anomaly detection\",\n            \"Predictive maintenance model integrated with maintenance management workflows\",\n            \"Executive command center with real-time operational status across all sites\"\n        ]\n    },\n    {\n        id: \"public-impact-programs\",\n        title: \"Public Impact & Strategic Programs\",\n        intro: \"Designing and executing technology initiatives funded by grants, public capital, or philanthropic mandates — ensuring compliance, scalability, and measurable outcomes from day one.\",\n        bullets: [\n            \"Architect program technology from the ground up around funder compliance and reporting requirements\",\n            \"Embed impact measurement into the system — not as a reporting add-on built after delivery\",\n            \"Design for geographic or programmatic scale from day one — not as a retrofit\",\n            \"Produce audit-ready funder reporting automatically, not through manual assembly before each cycle\"\n        ],\n        services: [\n            \"Program technology architecture design for grant, CSR, and public capital mandates\",\n            \"Implementation-ready program design aligned to donor and funder technical standards\",\n            \"Compliance, milestone, and audit tracking system implementation\",\n            \"Impact measurement dashboards with automated stakeholder and funder reporting\",\n            \"Scalable systems architecture for multi-region and multi-partner program expansion\"\n        ],\n        idealClient: \"Foundations, government agencies, and mission-driven organizations executing programs funded by grants, donor capital, or CSR mandates. Organizations that need to demonstrate measurable impact to maintain funding and public trust.\",\n        scenarios: [\n            \"A bilateral donor agency funding a $40M digital health program needs a technical partner who can design, build, and operate the data infrastructure — not just advise on it. PHAARVAI delivers the full implementation.\",\n            \"A corporate CSR program across 8 countries needs unified impact reporting for the annual report. A single data platform with standardized grantee input templates generates the report automatically.\",\n            \"A foundation deploying capital across 120 NGO grantees cannot assess portfolio performance in real time. A program management platform with outcome tracking and funder dashboards solves both problems.\",\n            \"A government ministry is designing a nationwide digital skilling program requiring World Bank compliance reporting. We architect the measurement framework, data system, and reporting layer before the program launches.\"\n        ],\n        deliverables: [\n            \"Program technology architecture aligned to funding body technical requirements\",\n            \"Automated impact tracking framework with structured funder reporting\",\n            \"Compliance and milestone management system with role-based access\",\n            \"Scalability roadmap for geographic expansion and program growth\"\n        ]\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/content/capabilities.ts\n");

